import boto3
import json
import psycopg2

def lambda_handler(event, context):
    conn = psycopg2.connect(
        "postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production"
    )
    
    cur = conn.cursor()
    cur.execute("SELECT * FROM production")
    
    rows = cur.fetchall()
    
    result = []
    for row in rows:
        result.append(dict(zip([desc[0] for desc in cur.description], row)))
        
    conn.close()
    
    return {
        'statusCode': 200,
        'body': json.dumps(result)
    }